mapper.select:
/* adm-master-timezone-sql-oracle.xml - selectTimezoneHd */
#{GRIDPAGING_ROWNUMTYPE_TOP}
        SELECT '0' AS CHK,
               TZKEY,
               UTCOFFSET,
               INSERTDATE,
               UPDATEDATE,
               INSERTURKEY,
	 		   UPDATEURKEY
          FROM TADMIN_MST_TZ_HD


			 	   #{SEARCH_CONDITION}


	    	  	   AND TZKEY = #{tzkey}





				ORDER BY #{colName} DESC


				ORDER BY #{colName} ASC



				ORDER BY UPDATEDATE DESC


#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		/* adm-master-timezone-sql-oracle.xml - selectTimezoneCountHd */
        SELECT COUNT(1)
          FROM TADMIN_MST_TZ_HD


				#{SEARCH_CONDITION}


				AND TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - checkTimezoneInfoHd */
		SELECT COUNT(1)
		  FROM TADMIN_MST_TZ_HD
    	 	WHERE TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - checkTimezoneContinentDtl */
		SELECT COUNT(1)
		  FROM TADMIN_MST_TZ_DT
		  WHERE TZKEY = #{tzkey}

    	 	AND TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - checkTimezoneCountryDtl */
		SELECT COUNT(1)
		  FROM TADMIN_MST_TZ_DT
		  WHERE TZKEY = #{tzkey}

    	 	AND TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - checkTimezoneCityDtl */
		SELECT COUNT(1)
		  FROM TADMIN_MST_TZ_DT
		  WHERE TZKEY = #{tzkey}

    	 	AND TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - checkTimezoneInfoDtl */
		SELECT COUNT(1)
		  FROM TADMIN_MST_TZ_DT
		  WHERE TZKEY = #{tzkey}

    	 	AND CONTINENTCD = #{continentcd}


    	 	AND CNTRYCD = #{cntrycd}


    	 	AND CITYCD = #{citycd}

mapper.insert:
		/* adm-master-timezone-sql-oracle.xml - insertTimezoneInfoHd */
		INSERT INTO TADMIN_MST_TZ_HD
		(
		      TZKEY
		    , UTCOFFSET
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
		)
		VALUES
		(
		     #{tzkey}
		    ,#{utcoffset}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

		/* adm-master-timezone-sql-oracle.xml - insertTimezoneInfoDtl */
		INSERT INTO TADMIN_MST_TZ_DT
		(
			  TZKEY
		    , CONTINENTCD
		    , CNTRYCD
		    , CITYCD
		    , DISPLAYMSG
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
		)
		VALUES
		(
		     #{tzkey}
		    ,#{continentcd}
		    ,#{cntrycd}
		    ,#{citycd}
		    ,#{displaymsg}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

mapper.update:
/* adm-master-timezone-sql-oracle.xml - updateTimezoneInfoHd */
UPDATE TADMIN_MST_TZ_HD
   SET UTCOFFSET   = #{utcoffset}
	 , UPDATEDATE   = #{sysdate}
	 , UPDATEURKEY  = #{surkey}
 WHERE TZKEY        = #{tzkey}

/* adm-master-timezone-sql-oracle.xml - updateTimezoneInfoDtl */
UPDATE TADMIN_MST_TZ_DT
   SET DISPLAYMSG 	  = #{displaymsg}
	  ,UPDATEDATE     = #{sysdate}
	  ,UPDATEURKEY    = #{surkey}
 WHERE TZKEY          = #{tzkey}
 	AND CONTINENTCD   = #{continentcd}
 	AND CNTRYCD	      = #{cntrycd}
 	AND CITYCD 	      = #{citycd}

mapper.delete:
/* adm-master-timezone-sql-oracle.xml - deleteTimezoneInfoHd */
DELETE FROM TADMIN_MST_TZ_HD
 WHERE TZKEY = #{tzkey}

	/* adm-master-timezone-sql-oracle.xml - deleteTimezoneInfoDtl */
	DELETE FROM TADMIN_MST_TZ_DT
	 WHERE TZKEY = #{tzkey}

    	 AND CONTINENTCD = #{continentcd}


      	 AND CNTRYCD = #{cntrycd}


    	 AND CITYCD = #{citycd}
